// api/preagreement/_pdf.js
// Server-side PDF of the (accepted) pre-agreement — the black-and-white
// paper replica of the real BOOM RENTAL PROPOSAL (parties, property, lease
// term, financial terms, general conditions 5.x, signatures, Egidi footer).
// Attached to the client/admin confirmation emails so the signed document
// travels WITH the email, exactly like the scanned originals did.
//
// pdf-lib is imported statically — a lazy await import() is not traced by
// Vercel's bundler and fails at runtime in production.

import { PDFDocument, StandardFonts, rgb } from 'pdf-lib';

// The real BOOM sonic-rings mark (black, on transparent) — rasterized once
// from the official site SVG and embedded so the PDF carries the brand with
// zero runtime dependencies.
const LOGO_PNG_B64 = '';

const A4 = [595.28, 841.89];
const M = 56;                       // page margin
const W = A4[0] - M * 2;            // text width
const INK = rgb(0.07, 0.07, 0.07);
const SOFT = rgb(0.45, 0.45, 0.45);
const GOLD = rgb(0.54, 0.43, 0.11);
const LINE = rgb(0.88, 0.88, 0.88);

const eur = n => '€' + Number(n || 0).toLocaleString('en-US', {
  minimumFractionDigits: Math.round(Number(n || 0) * 100) % 100 !== 0 ? 2 : 0,
  maximumFractionDigits: 2,
});
const fmtD = s => { try { return new Date(String(s).slice(0, 10) + 'T00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' }); } catch { return String(s || ''); } };
// pdf-lib's WinAnsi cannot encode every glyph phones type — normalize.
const clean = s => String(s == null ? '' : s)
  .replace(/[‘’′]/g, "'").replace(/[“”]/g, '"')
  .replace(/[–—]/g, '-').replace(/→/g, '->')
  .replace(/[^\x20-\x7E\xA0-\xFF\u20AC]/g, '');

export async function buildPaPdf(pa) {
  const p = pa.property || {}, le = pa.lease || {}, m = pa.money || {};
  const tenants = Array.isArray(pa.tenants) && pa.tenants.length ? pa.tenants : (pa.tenant ? [pa.tenant] : []);
  const inc = m.utilities === 'included';
  const ec = inc ? 0 : (Number(m.energyCredit) || 0);
  const split = m.depositSplitPct != null ? Number(m.depositSplitPct) : 100;

  const pdf = await PDFDocument.create();
  const font = await pdf.embedFont(StandardFonts.Helvetica);
  const bold = await pdf.embedFont(StandardFonts.HelveticaBold);
  const italic = await pdf.embedFont(StandardFonts.HelveticaOblique);
  const logo = await pdf.embedPng(Buffer.from(LOGO_PNG_B64, 'base64')).catch(() => null);

  let page = pdf.addPage(A4);
  let y = A4[1] - M;

  const foot = pg => {
    pg.drawText('Egidi Immobiliare S.r.l.     P.IVA 17322991005     boomrome.com', { x: M, y: 34, size: 8, font, color: SOFT });
  };
  const need = h => {
    if (y - h < 70) { foot(page); page = pdf.addPage(A4); y = A4[1] - M; }
  };
  const wrap = (text, f, size, width) => {
    const words = clean(text).split(/\s+/); const lines = []; let cur = '';
    for (const w of words) {
      const t = cur ? cur + ' ' + w : w;
      if (f.widthOfTextAtSize(t, size) > width && cur) { lines.push(cur); cur = w; }
      else cur = t;
    }
    if (cur) lines.push(cur);
    return lines;
  };
  const para = (text, f, size, color, width = W, lh = 1.45, x = M) => {
    for (const ln of wrap(text, f, size, width)) {
      need(size * lh + 2);
      page.drawText(ln, { x, y, size, font: f, color });
      y -= size * lh;
    }
  };
  // Section header exactly like the paper: "1 .   P A R T I E S"
  const secTitle = (no, title) => {
    need(44);
    y -= 18;
    page.drawText(`${no}.`, { x: M, y, size: 12, font: bold, color: INK });
    page.drawText(clean(title).toUpperCase(), { x: M + 22, y, size: 12, font: bold, color: INK, characterSpacing: 4 });
    y -= 20;
  };
  // The paper's bordered label/value table. rows: [label, value] — value may
  // hold every co-tenant's data joined with ' · ' exactly like the original.
  const LBL_W = 150;
  const table = rows => {
    for (const [k, v] of rows) {
      const vLines = wrap(v || '-', bold, 9.5, W - LBL_W - 24);
      const rh = Math.max(26, vLines.length * 13 + 14);
      need(rh);
      const top = y + 12;
      page.drawRectangle({ x: M, y: top - rh, width: W, height: rh, borderColor: LINE, borderWidth: .7 });
      page.drawLine({ start: { x: M + LBL_W, y: top - rh }, end: { x: M + LBL_W, y: top }, thickness: .7, color: LINE });
      page.drawText(clean(k), { x: M + 10, y: top - 17, size: 9, font, color: SOFT });
      let vy = top - 17;
      for (const ln of vLines) { page.drawText(ln, { x: M + LBL_W + 12, y: vy, size: 9.5, font: bold, color: INK }); vy -= 13; }
      y -= rh;
    }
    y -= 6;
  };
  // Financial table: Item | Amount with a bold TOTAL row (as on the paper).
  const moneyTable = rows => {
    need(24);
    const top0 = y + 12;
    page.drawText('Item', { x: M + 10, y: top0 - 15, size: 9.5, font: bold, color: INK });
    page.drawText('Amount', { x: M + W - 130, y: top0 - 15, size: 9.5, font: bold, color: INK });
    page.drawRectangle({ x: M, y: top0 - 22, width: W, height: 22, borderColor: LINE, borderWidth: .7 });
    y -= 22;
    for (const r of rows) {
      const dLines = wrap(r.desc, r.total ? bold : font, r.total ? 10 : 9.5, W - 160);
      const rh = Math.max(30, dLines.length * 13 + 16);
      need(rh);
      const top = y + 12;
      page.drawRectangle({ x: M, y: top - rh, width: W, height: rh, borderColor: LINE, borderWidth: .7 });
      let dy = top - 18;
      for (const ln of dLines) { page.drawText(ln, { x: M + 10, y: dy, size: r.total ? 10 : 9.5, font: r.total ? bold : font, color: INK }); dy -= 13; }
      const amt = clean(r.amount);
      page.drawText(amt, { x: M + W - 12 - bold.widthOfTextAtSize(amt, r.total ? 11 : 10), y: top - 19, size: r.total ? 11 : 10, font: bold, color: INK });
      y -= rh;
    }
    y -= 6;
  };
  // Join one field across every tenant with the paper's ' · ' separator.
  const across = get => tenants.map(get).map(v => (v || '').trim()).filter(Boolean).join(' \u00B7 ') || '-';

  // ── letterhead: logo in its bordered plate + BOOM, exactly like the paper ──
  const plateH = 46;
  page.drawRectangle({ x: M, y: y - plateH + 12, width: 210, height: plateH, borderColor: rgb(.75,.75,.75), borderWidth: .8 });
  if (logo) page.drawImage(logo, { x: M + 8, y: y - plateH + 18, width: 34, height: 34 });
  page.drawText('BOOM', { x: M + 54, y: y - plateH + 28, size: 21, font: bold, color: INK, characterSpacing: 5 });
  if (pa.ref) {
    const refTxt = `N. ${clean(pa.ref)}`;
    const wRef = bold.widthOfTextAtSize(refTxt, 10);
    page.drawRectangle({ x: A4[0] - M - wRef - 20, y: y - 8, width: wRef + 20, height: 24, borderColor: INK, borderWidth: .8 });
    page.drawText(refTxt, { x: A4[0] - M - wRef - 10, y: y - 1, size: 10, font: bold, color: INK });
    const st = pa.status === 'paid' ? `PAID ${pa.paidEur ? eur(pa.paidEur) : ''}` : 'ACCEPTED';
    page.drawText(clean(st), { x: A4[0] - M - bold.widthOfTextAtSize(st, 8) - 14, y: y - 22, size: 8, font: bold, color: GOLD });
  }
  y -= plateH + 6;
  page.drawText('Premium Apartment Rentals', { x: M, y, size: 8.5, font: italic, color: SOFT });
  y -= 26;
  page.drawText('RENTAL PROPOSAL', { x: M, y, size: 21, font: bold, color: INK, characterSpacing: 3 });
  y -= 15;
  page.drawText(clean(`Pre-Agreement for ${le.type || 'Transitional Lease'}`), { x: M, y, size: 9.5, font, color: SOFT });
  y -= 4;

  // ── 1. PARTIES ──
  secTitle(1, 'Parties');
  page.drawText('L A N D L O R D', { x: M, y, size: 8, font: bold, color: INK }); y -= 14;
  para((pa.landlord || {}).name || '-', bold, 10.5, INK); y -= 8;
  page.drawText(tenants.length > 1 ? 'T E N A N T S' : 'T E N A N T', { x: M, y, size: 8, font: bold, color: INK }); y -= 20;
  table([
    ['Full Name', across(t => t.fullName)],
    ['Date of Birth', across(t => t.dob)],
    ['Place of Birth', across(t => t.birthPlace)],
    ['Nationality', across(t => t.nationality)],
    ['Current Address', across(t => t.address)],
    ['Tax Code (C.F.)', across(t => t.cf)],
    ['ID / Passport No.', across(t => t.idDoc)],
    ['Email', across(t => t.email)],
    ['Phone', across(t => t.phone)],
  ]);

  // ── 2. PROPERTY ──
  secTitle(2, 'Property');
  para('The Landlord grants the Tenant the use of an apartment located at:', font, 9.5, INK);
  para(p.address || '-', bold, 11.5, INK); y -= 8;
  table([
    ['Type', p.type || 'Entire Apartment'],
    ['Condition', p.condition || 'Furnished'],
    ['Use', p.use || 'Residential'],
    ...(p.floor ? [['Floor', p.floor]] : []),
    ...(p.unit ? [['Unit', p.unit]] : []),
  ]);

  // ── 3. LEASE TERM ──
  secTitle(3, 'Lease Term');
  para('The lease shall have the following duration:', font, 9.5, INK); y -= 8;
  table([
    ['Start Date', fmtD(le.startDate)],
    ['Initial Duration', `${le.months || '-'} months`],
    ['End Date', fmtD(le.endDate)],
  ]);

  // ── 4. FINANCIAL TERMS ──
  secTitle(4, 'Financial Terms');
  const rows = [];
  const monthlyTotal = m.monthlyTotal != null ? m.monthlyTotal : (Number(m.rent) || 0) + ec;
  rows.push(ec > 0
    ? { desc: `Monthly base Rent ${eur(m.rent)} + Energy Credit ${eur(ec)} (total ${eur(monthlyTotal)}/month)`, amount: eur(monthlyTotal) }
    : { desc: `Monthly Rent${inc ? ' (all utilities included)' : ''}`, amount: eur(m.rent) });
  const depDesc = split > 0 && split < 100
    ? `Security Deposit - ${m.depositMonths} month's base rent (${split}% due at signing, ${100 - split}% due upon move-in)`
    : `Security Deposit - ${m.depositMonths} month's base rent (refundable)`;
  rows.push({ desc: depDesc, amount: eur(m.deposit) });
  (pa.extras || []).forEach(x => rows.push({ desc: x.label, amount: eur(x.amount) }));
  rows.push({ desc: 'TOTAL DUE AT SIGNING', amount: eur(m.dueAtSigning), total: true });
  moneyTable(rows);
  const feeAmt = m.feeMode === 'months'
    ? `${m.feeMonths || 1} month's base rent = ${eur(m.fee)}`
    : (m.feeMode === 'flat' || m.feeFlat != null) ? `${eur(m.fee)} (fixed)`
    : `${m.feePct != null ? m.feePct : 12}% of annual rent = ${eur(m.fee)}`;
  const feeWhen = m.feeDue === 'move-in' ? 'due upon move-in, not at pre-agreement signing'
    : m.feeDue === 'signing' ? 'due at signing (included in the total above)'
    : 'due separately, not at signing';
  para(Number(m.fee) > 0
    ? `Note: Agency fee: ${feeAmt}${m.feeVatPct ? ` + VAT ${m.feeVatPct}% (${eur(m.feeVat)}) = ${eur(m.feeTotal)}` : ''} - ${feeWhen}.${tenants.length > 1 ? ' All co-tenants are jointly and severally liable for the full rent and obligations under this agreement.' : ''}${pa.note ? ' ' + pa.note : ''}`
    : `Note: Agency fee: none for this agreement.${tenants.length > 1 ? ' All co-tenants are jointly and severally liable for the full rent and obligations under this agreement.' : ''}${pa.note ? ' ' + pa.note : ''}`, italic, 8.5, SOFT);

  // ── 5. GENERAL CONDITIONS ──
  secTitle(5, 'General Conditions');
  const conds = [
    "The security deposit shall be returned at the end of the lease (within 15 days after move-out / keys hand over), subject to verification of the property's condition and settlement of any outstanding utility balance. Normal wear and tear caused by ordinary and reasonable use of the property shall not be deemed damage and shall not be deducted from the security deposit.",
    'The security deposit shall be fully returned if the Landlord cancels the agreement for any reason, or if the Tenant cancels with justified cause.',
    'The Tenant shall maintain the property in good condition and promptly report any defects or issues.',
    'Monthly rent shall be paid by the 5th of each month via bank transfer.',
  ];
  if (ec > 0) conds.push(`The monthly payment of ${eur(monthlyTotal)} consists of: (a) base rent of ${eur(m.rent)} and (b) an energy allowance of ${eur(ec)} included in the monthly fee. The energy allowance of ${eur(ec)}/month covers electricity consumption up to ${eur(ec)}. Should monthly electricity costs exceed ${eur(ec)}, the Tenant shall pay only the surplus (the amount exceeding ${eur(ec)}) directly to the Landlord upon presentation of the utility bill. If monthly electricity consumption is equal to or below ${eur(ec)}, no additional charge applies.`);
  if (le.reason) conds.push(`Transitional need: ${le.reason}.`);
  conds.push(inc
    ? 'All utilities (electricity, gas, water, internet) are included in the monthly rent, within fair and ordinary use of the property.'
    : `${ec > 0 ? 'All other utilities (gas, water, internet)' : 'All utilities (electricity, gas, water, internet)'} are excluded from the monthly rent and are the sole responsibility of the Tenant.`);
  if (tenants.length > 1) conds.push('All co-tenants are jointly and severally liable for the full rent and all obligations hereunder.');
  (pa.customClauses || []).forEach(c => conds.push(c));
  conds.push('Any changes to these terms must be agreed upon in writing by both parties.');
  conds.forEach((c, i) => {
    need(14);
    page.drawText(`5.${i + 1}`, { x: M, y, size: 8.5, font: bold, color: INK });
    para(c, font, 8.5, INK, W - 28, 1.42, M + 28);
    y -= 3;
  });

  // ── 6. SIGNATURES ──
  secTitle(6, 'Signatures');
  const when = pa.acceptedAt ? fmtD(pa.acceptedAt) : fmtD(new Date().toISOString());
  para(`Roma, ${when}`, font, 9.5, INK); y -= 6;
  need(110);
  const colW = W / 2 - 12;
  const boxTop = y;
  [['L A N D L O R D', (pa.landlord || {}).name || '', M], [tenants.length > 1 ? 'T E N A N T S' : 'T E N A N T', tenants.map(t => t.fullName).filter(Boolean).join(' \u00B7 '), M + colW + 24]].forEach(([cap, who, x]) => {
    page.drawText(cap, { x, y: boxTop, size: 8, font: bold, color: INK });
    page.drawRectangle({ x, y: boxTop - 74, width: colW, height: 62, borderColor: LINE, borderWidth: .8 });
    page.drawText('(signature)', { x: x + 8, y: boxTop - 24, size: 6.5, font: italic, color: SOFT });
    const sigNames = cap.startsWith('T') ? tenants.map(t => t.signature || t.fullName).filter(Boolean) : [who];
    let sy = boxTop - 42;
    sigNames.slice(0, 3).forEach(n => { page.drawText(clean(n), { x: x + 12, y: sy, size: sigNames.length > 2 ? 9.5 : 12, font: italic, color: INK }); sy -= sigNames.length > 2 ? 12 : 15; });
    page.drawText(clean(who).slice(0, 62), { x, y: boxTop - 86, size: 7.5, font, color: SOFT });
  });
  y = boxTop - 102;
  if (pa.consent && pa.consent.at) {
    para(`Digitally accepted with typed signature(s) - recorded ${String(pa.consent.at).replace('T', ' ').slice(0, 16)} UTC - IP ${pa.consent.ip || '-'} - boomrome.com/pre-agreement`, font, 7, SOFT);
  }

  foot(page);
  const bytes = await pdf.save();
  return Buffer.from(bytes);
}
